-- Spine 2.0 catalogue cleanup: deprecate out-of-scope bands + merge legacy category slugs
-- Generated by scripts/generate-catalogue-cleanup-sql.mjs
-- Idempotent: safe to re-run.

BEGIN;

-- Deprecate pre-Spine 2.0 pilot bands (history preserved, hidden from Discover).

UPDATE public.pl_age_bands ab
SET
  is_active = false,
  label = CASE
    WHEN ab.label LIKE '%[deprecated — pre-Spine 2.0]%' THEN ab.label
    ELSE ab.label || ' [deprecated — pre-Spine 2.0]'
  END,
  updated_at = now()
WHERE ab.id IN ('6-9m', '22-24m', '25-27m', '28-30m', '31-33m', '34-36m');

UPDATE public.pl_age_band_development_need_category_types
SET is_active = false, updated_at = now()
WHERE age_band_id IN ('6-9m', '22-24m', '25-27m', '28-30m', '31-33m', '34-36m');

UPDATE public.pl_age_band_ux_wrappers
SET is_active = false, updated_at = now()
WHERE age_band_id IN ('6-9m', '22-24m', '25-27m', '28-30m', '31-33m', '34-36m');

UPDATE public.pl_age_band_category_type_products
SET is_active = false, updated_at = now()
WHERE age_band_id IN ('6-9m', '22-24m', '25-27m', '28-30m', '31-33m', '34-36m');



-- ent_cat_animal_mini_books → cat_animal_mini_books
DO $$
BEGIN
  IF EXISTS (SELECT 1 FROM public.pl_category_types WHERE slug = 'ent_cat_animal_mini_books')
     AND NOT EXISTS (SELECT 1 FROM public.pl_category_types WHERE slug = 'cat_animal_mini_books') THEN
